17	// CSRFHeaderName is the HTTP header that must carry the server-issued CSRF
18	// token on operatorPromptSubmit calls (FEAT operator-prompts, Story 15).
19	const CSRFHeaderName = "X-CSRF-Token"
20	
21	// OperatorPromptIdempotencyTTL is the window during which duplicate
22	// idempotency keys deduplicate to the original bead.
23	const OperatorPromptIdempotencyTTL = 24 * time.Hour
24	
25	// OperatorPromptEventKind is the BeadEvent.Kind appended to every
26	// operator-prompt bead's audit log on submit, capturing the originating
27	// identity (localhost OR ts-net WhoIs).
28	const OperatorPromptEventKind = "operator_prompt_submit"
29	
30	// OperatorPromptApproveEventKind is the BeadEvent.Kind appended to an
31	// operator-prompt bead's audit log when it transitions proposed → open
32	// (either via operatorPromptApprove or via the auto-approve path on
33	// operatorPromptSubmit).
34	const OperatorPromptApproveEventKind = "operator_prompt_approve"
35	
36	// OperatorPromptCancelEventKind is the BeadEvent.Kind appended to an
37	// operator-prompt bead's audit log when it transitions proposed → cancelled
38	// via operatorPromptCancel.
39	const OperatorPromptCancelEventKind = "operator_prompt_cancel"
40	
41	// OperatorPromptAllowlistLocalhostSentinel is the sentinel allowlist entry
42	// that grants any localhost-kind identity auto-approve / approve rights.
43	// Per the locked Story 15 decision, ts-net identities are never eligible
44	// regardless of the allowlist contents.
45	const OperatorPromptAllowlistLocalhostSentinel = "localhost"
46	
47	// httpRequestKey is the context key used by the server to plumb the
48	// originating *http.Request into GraphQL resolver calls so the resolver can
49	// validate CSRF tokens and capture the originating identity.
50	type httpRequestKey struct{}
51	
52	// WithHTTPRequest returns ctx with r attached for downstream resolver access.
53	// The server's GraphQL HTTP handler must call this before delegating to the
54	// gqlgen handler so resolvers that depend on request headers (CSRF token,
55	// X-Tailscale-User) work correctly.
56	func WithHTTPRequest(ctx context.Context, r *http.Request) context.Context {
57		return context.WithValue(ctx, httpRequestKey{}, r)
58	}
59	
60	// httpRequestFromContext retrieves the *http.Request previously attached via
61	// WithHTTPRequest, or nil if none was set.
62	func httpRequestFromContext(ctx context.Context) *http.Request {
63		if v, ok := ctx.Value(httpRequestKey{}).(*http.Request); ok {
64			return v
65		}
66		return nil
67	}
